// ---------- level-one memory workbench ----------
const panel = document.getElementById("panel");
const panelTitle = document.getElementById("panel-title");
const panelBody = document.getElementById("panel-body");
const panelFoot = document.getElementById("panel-foot");
const aiLine = document.getElementById("ai-line");
const stabilityPips = document.getElementById("stability-pips");
const stabilityCount = document.getElementById("stability-count");
const memorySlot = document.getElementById("memory-slot");
const memoryOptions = document.getElementById("memory-options");
const memoryFeedback = document.getElementById("memory-feedback");
const terminalOutput = document.getElementById("terminal-output");
const beginReconstruction = document.getElementById("begin-reconstruction");
const commitMemory = document.getElementById("commit-memory");
const stagePanes = [...document.querySelectorAll("[data-pane]")];
const stepNodes = [...document.querySelectorAll("[data-step-node]")];

const WORKFLOW_STEPS = ["intro", "reconstruct", "diff", "commit", "complete"];
const MAX_STABILITY = 3;
const MEMORY_LINE = "Marked the gold island as the landing site before signal loss.";
const MEMORY_OPTIONS = [
  {
    text: MEMORY_LINE,
    correct: true,
    feedback: "Memory consistency check passed. The recovered line matches the helmet transcript.",
  },
  {
    text: "Diverted engine power to reopen the cargo bay before liftoff.",
    correct: false,
    feedback: "That contradicts the evidence. The helmet never mentions engines or cargo systems.",
  },
  {
    text: "Returned safely to orbit after the island survey completed.",
    correct: false,
    feedback: "That cannot be stable. The transcript ends before any return to orbit.",
  },
];
const AI_LINES = {
  intro: "I found evidence, but evidence is not memory. Help me reconstruct a stable record.",
  reconstruct: "Choose the line that belongs in the ship memory file. Wrong context weakens the buffer.",
  diff: "Good. Now review the actual change before it becomes part of history.",
  commit: "The commit is being written. Watch how the checkpoint is created around committed work.",
  complete: "Checkpoint sealed. I can now recover the commit, intent, and transcript later.",
};
const COMMIT_LINES = [
  '$ git commit -m "Restore EVA-03 landing-site memory"',
  "",
  "[main a17c9e2] Restore EVA-03 landing-site memory",
  " 1 file changed, 1 insertion(+), 1 deletion(-)",
  "",
  "$ entire hooks git post-commit",
  "condensing active session transcript...",
  "linking commit a17c9e2 to checkpoint 9f42c8a1d6b3",
  "",
  "Entire-Checkpoint: 9f42c8a1d6b3",
];

// The artifact context for the panel that's currently open. islandView hands us
// the fragment plus how to mark it checkpointed and how to read overall progress.
let panelCtx = null;
let stability = MAX_STABILITY;
let currentStep = "intro";
let commitTimers = [];

function renderFoot(progress) {
  if (!progress) { panelFoot.textContent = "find evidence · change memory · commit · checkpoint"; return; }
  const { recovered, total } = progress;
  panelFoot.textContent = recovered >= total
    ? "level complete · checkpointed memory restored"
    : `checkpointed memories · ${recovered}/${total}`;
}

function clearCommitTimers() {
  for (const timer of commitTimers) clearTimeout(timer);
  commitTimers = [];
}

function renderStability() {
  stabilityPips.innerHTML = "";
  for (let i = 0; i < MAX_STABILITY; i++) {
    const pip = document.createElement("span");
    pip.className = i < stability ? "is-live" : "is-lost";
    stabilityPips.append(pip);
  }
  stabilityCount.textContent = `${stability}/${MAX_STABILITY}`;
}

function setStep(step) {
  currentStep = step;
  panel.dataset.step = step;
  stagePanes.forEach((pane) => {
    pane.classList.toggle("hidden", pane.dataset.pane !== step);
  });

  const currentIndex = WORKFLOW_STEPS.indexOf(step);
  stepNodes.forEach((node) => {
    const nodeIndex = WORKFLOW_STEPS.indexOf(node.dataset.stepNode);
    node.classList.toggle("is-active", nodeIndex === currentIndex);
    node.classList.toggle("is-done", nodeIndex < currentIndex);
  });

  aiLine.textContent = AI_LINES[step];
}

function renderOptions() {
  memoryOptions.innerHTML = "";
  for (const option of MEMORY_OPTIONS) {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "memory-choice";
    button.textContent = option.text;
    button.addEventListener("click", () => chooseMemory(option, button));
    memoryOptions.append(button);
  }
}

function resetPuzzle() {
  stability = MAX_STABILITY;
  memorySlot.textContent = "[MISSING]";
  memorySlot.classList.remove("is-filled", "is-error");
  memoryFeedback.textContent = "";
  memoryFeedback.className = "memory-feedback";
  renderStability();
  renderOptions();
}

function chooseMemory(option, button) {
  if (currentStep !== "reconstruct") return;
  memorySlot.textContent = option.text;
  memorySlot.classList.toggle("is-filled", option.correct);
  memorySlot.classList.toggle("is-error", !option.correct);
  memoryFeedback.textContent = option.feedback;
  memoryFeedback.className = `memory-feedback ${option.correct ? "is-good" : "is-bad"}`;

  if (option.correct) {
    [...memoryOptions.children].forEach((child) => { child.disabled = true; });
    button.classList.add("is-selected");
    setTimeout(() => setStep("diff"), 850);
    return;
  }

  stability -= 1;
  renderStability();
  button.disabled = true;
  button.classList.add("is-wrong");

  if (stability <= 0) {
    memoryFeedback.textContent = "Context buffer collapsed. Restoring the last stable state...";
    memoryFeedback.className = "memory-feedback is-bad is-collapse";
    [...memoryOptions.children].forEach((child) => { child.disabled = true; });
    setTimeout(resetPuzzle, 1200);
  }
}

function playCommitSequence() {
  clearCommitTimers();
  terminalOutput.textContent = "";
  setStep("commit");

  COMMIT_LINES.forEach((line, index) => {
    const timer = setTimeout(() => {
      terminalOutput.textContent += `${line}\n`;
      terminalOutput.scrollTop = terminalOutput.scrollHeight;
      if (index === COMMIT_LINES.length - 1) {
        commitTimers.push(setTimeout(completeCheckpoint, 700));
      }
    }, index * 360);
    commitTimers.push(timer);
  });
}

function completeCheckpoint() {
  clearCommitTimers();
  const progress = panelCtx?.onComplete?.();
  panelCtx.checkpointed = true;
  renderFoot(progress);
  setStep("complete");
}

function openPanel(frag, ctx = {}) {
  clearCommitTimers();
  panelCtx = ctx;
  panelTitle.textContent = frag.title;
  panelBody.textContent = "Recover the missing context from this helmet logger, commit the memory file, and let Entire create the checkpoint tied to that work.";
  resetPuzzle();
  renderFoot(ctx.progress);
  setStep(ctx.checkpointed ? "complete" : "intro");
  panel.classList.remove("hidden");
}
function closePanel() {
  clearCommitTimers();
  panel.classList.add("hidden");
}

beginReconstruction?.addEventListener("click", () => setStep("reconstruct"));
commitMemory?.addEventListener("click", playCommitSequence);
document.getElementById("panel-close").addEventListener("click", closePanel);
window.addEventListener("keydown", (e) => { if (e.key === "Escape") closePanel(); });

