  transition: transform 0.45s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.45s;
}

#panel.hidden {
  transform: translateX(110%);
  opacity: 0;
  pointer-events: none;
}

#panel-tag {
  font-size: 11px;
  letter-spacing: 0.3em;
  color: var(--accent);
  opacity: 0.8;
}

#panel h2 {
  margin: 10px 0 18px;
  font-size: 24px;
  font-weight: 600;
  letter-spacing: 0.04em;
  line-height: 1.2;
}

#panel p {
  font-size: 14px;
  line-height: 1.7;
  opacity: 0.82;
}

#panel-foot {
  position: absolute;
  bottom: 34px;
  left: 38px;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  opacity: 0.4;
}

/* Checkpoint offer inside the inspection panel */
#panel-checkpoint {
  margin-top: 26px;
  padding-top: 22px;
  border-top: 1px solid rgba(111, 227, 255, 0.18);
}

.ckpt-q {
  font-size: 13px;
  letter-spacing: 0.04em;
  color: var(--accent);
  margin-bottom: 10px;
}

.ckpt-explainer {
  font-size: 13px;
  line-height: 1.65;
  opacity: 0.78;
  margin-bottom: 18px;
}

.ckpt-explainer strong {
  color: var(--ink);
  opacity: 1;
  font-weight: 600;
}

#ckpt-create {
  width: 100%;
  padding: 13px 16px;
  font: inherit;
  font-size: 12px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #04121c;
  background: var(--accent);
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.2s ease;
  box-shadow: 0 6px 22px rgba(111, 227, 255, 0.28);
}

#ckpt-create:hover {
  transform: translateY(-1px);
  box-shadow: 0 10px 30px rgba(111, 227, 255, 0.42);
}

#ckpt-create:active { transform: translateY(0); }

/* :not(.hidden) so the ID rule doesn't out-specificity .hidden's display:none */
#ckpt-done:not(.hidden) {
  display: flex;
  align-items: center;
  gap: 14px;
}

.ckpt-check {
  flex: none;
  width: 34px;
  height: 34px;
  display: grid;
  place-items: center;
  border-radius: 50%;
  background: rgba(111, 227, 255, 0.16);
  border: 1px solid var(--accent);
  color: var(--accent);
  font-size: 16px;
}

.ckpt-done-title { font-size: 14px; letter-spacing: 0.04em; }
.ckpt-done-sub { font-size: 12px; opacity: 0.6; margin-top: 3px; }

#panel-close {
  position: absolute;
  top: 26px;
  right: 28px;
  width: 38px;
  height: 38px;
  border: 1px solid rgba(232, 244, 255, 0.25);
  background: transparent;
  color: var(--ink);
  font-size: 20px;
  border-radius: 50%;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
}

#panel-close:hover {
  background: rgba(111, 227, 255, 0.12);
  border-color: var(--accent);
}

/* Map pin marking the landable island */
#island-pin {
  position: fixed;
  top: 0; left: 0;
  transform: translate(-50%, -100%);
  padding: 0;
  background: none;
  border: none;
  cursor: pointer;
  pointer-events: auto;
  z-index: 15;
  transition: filter 0.2s ease, transform 0.18s cubic-bezier(0.22, 1, 0.36, 1);
  transform-origin: bottom center;
  filter:
    drop-shadow(0 2px 4px var(--pin-shadow))
    drop-shadow(0 0 6px rgba(255, 184, 107, 0.3));
}
#island-pin .pin-svg { display: block; }
#island-pin .pin-svg path {
  fill: var(--pin-shell);
  stroke: var(--pin-rim);
  stroke-width: 1.35;
}
#island-pin .pin-svg circle {
  fill: var(--pin-core);
}
/* Hover (or keyboard focus, or synced from the 3D region) lifts the pin. */
#island-pin:hover,
#island-pin:focus-visible,
#island-pin.is-hot {
  transform: translate(-50%, -100%) scale(1.12);
  filter:
    drop-shadow(0 3px 5px var(--pin-shadow))
    drop-shadow(0 0 12px rgba(255, 184, 107, 0.62));
  outline: none;
}

/* Crossfade overlay between views */
#fade {
  position: fixed;
  inset: 0;
  background: #07050f;
  opacity: 0;
  pointer-events: none;
  z-index: 40;
  transition: opacity 0.65s ease;
}
#fade.show { opacity: 1; }

/* First-person island HUD */
#crosshair {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 10px;
  height: 10px;
  margin: -5px 0 0 -5px;
  border: 1.5px solid rgba(255, 244, 232, 0.7);
  border-radius: 50%;
  box-shadow: 0 0 8px rgba(255, 210, 122, 0.6);
}

#fp-prompt {
  position: absolute;
  bottom: 138px;
  left: 50%;
  transform: translateX(-50%);
  width: max-content;
  max-width: calc(100vw - 36px);
  padding: 12px 22px;
  background: rgba(8, 14, 26, 0.7);
  border: 1px solid rgba(255, 210, 122, 0.4);
  border-radius: 6px;
  font-size: 14px;
  line-height: 1.45;
  letter-spacing: 0.12em;
  color: var(--ink);
  text-align: center;
  text-shadow: 0 0 12px rgba(255, 210, 122, 0.4);
}

#fp-controls {
  position: absolute;
  right: 28px;
  bottom: 28px;
  max-width: min(720px, calc(100vw - 56px));
  padding: 9px 12px;
  background: rgba(8, 14, 26, 0.54);
  border: 1px solid rgba(255, 244, 232, 0.18);
  border-radius: 6px;
  color: rgba(232, 244, 255, 0.72);
  font-size: 10px;
  line-height: 1;
  letter-spacing: 0;
}

#fp-controls:not(.hidden) {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: 10px 14px;
}

.control-item {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  min-height: 28px;
  white-space: nowrap;
}

.control-label {
  color: rgba(232, 244, 255, 0.68);
  letter-spacing: 0.05em;
}

.key {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 20px;
  padding: 0 5px;
  border: 1px solid rgba(255, 244, 232, 0.26);
  border-radius: 4px;
  background: rgba(255, 244, 232, 0.08);
  color: var(--ink);
  font-size: 10px;
  font-weight: 600;
  line-height: 1;
  box-shadow: inset 0 -1px 0 rgba(2, 4, 10, 0.4);
}

.key-wide {
  min-width: 30px;
}

.arrow-keys {
  display: grid;
  grid-template-columns: repeat(3, 18px);
  grid-template-rows: repeat(2, 18px);
  gap: 2px;
}

.arrow-keys .key {
  min-width: 18px;
  width: 18px;
  height: 18px;
  padding: 0;
  font-size: 9px;
}

.key-up { grid-column: 2; grid-row: 1; }
.key-left { grid-column: 1; grid-row: 2; }
.key-down { grid-column: 2; grid-row: 2; }
.key-right { grid-column: 3; grid-row: 2; }

.mouse-hint {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: rgba(232, 244, 255, 0.82);
}

.mouse-icon {
  position: relative;
  width: 13px;
  height: 19px;
  border: 1px solid rgba(255, 244, 232, 0.5);
  border-radius: 8px;
  background: rgba(255, 244, 232, 0.08);
}

.mouse-icon::before {
  content: "";
  position: absolute;
  top: 4px;
  left: 50%;
  width: 2px;
  height: 5px;
  transform: translateX(-50%);
  border-radius: 2px;
  background: rgba(255, 210, 122, 0.72);
}

@media (max-width: 680px) {
  #hint {
    bottom: 72px;
    max-width: calc(100vw - 36px);
    text-align: center;
    white-space: normal;
  }

  #audio-panel {
    top: auto;
    right: auto;
    bottom: 22px;
    left: 18px;
    gap: 6px;
    padding: 7px 8px;
  }

  .audio-mark {
    width: 28px;
    height: 28px;
  }

  .icon-button {
    width: 28px;
    height: 28px;
  }

  #audio-volume {
    width: 78px;
  }

  #fp-controls {
    top: 116px;
    right: 18px;
    bottom: auto;
    max-width: calc(100vw - 36px);
  }

  #fp-prompt {
    bottom: 82px;
  }
}

/* Loader */
#loader {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 22px;
  background: #02040a;
  z-index: 50;
  transition: opacity 0.8s ease;
}

#loader.done {
  opacity: 0;
  pointer-events: none;
}

.loader-ring {
  width: 46px;
  height: 46px;
  border: 2px solid rgba(111, 227, 255, 0.2);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.9s linear infinite;
}

.loader-text {
  font-size: 12px;
  letter-spacing: 0.35em;
  opacity: 0.7;
}

@keyframes spin { to { transform: rotate(360deg); } }

.hidden { display: none; }

